var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"으아아아악!!","JPN":"うわああああ！!","ENG":"Aaaack!!","TWN":"啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"죽어!! 죽어버려!! 이 빌어먹을 개자식들아!!","JPN":"死ね！！　死んでしまえ！！　このクソ野郎ども！！","ENG":"Die!! DIE!! You creepy bastards!!","TWN":"去死吧！全都去死！！你們這些畜生！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"정신차려 신참!! 튀어나가지 말고 대형을 유지해!!","JPN":"落ち着け、新米！！　飛び出るな、隊形を維持しろ！！","ENG":"Get a hold of yourself, rookie!! Stop falling out of line and keep formation!!","TWN":"菜鳥，你冷靜點！不要亂跑，要維持隊形！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"진정? 방금 보셨지 않습니까, 중대장님!!","JPN":"落ち着く？　今の見ませんでしたか、中隊長！！","ENG":"What? But sir! Didn't you see what just happened?!","TWN":"冷靜？中隊長，你剛沒看到嗎！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"저 녀석들이 눈 앞에서 글렌 녀석을 갈갈이 찢어버렸다고요!!","JPN":"あいつらが目の前でグレンのやつを八つ裂きにしやがったんですよ！！","ENG":"Those scum tore up Glen right in front of our eyes!!","TWN":"那些畜生就在我們的眼前，將格倫那小子給分屍欸！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"제길, 누가 그걸 모르나!? 죽기 싫으면 정신 차리고 조준 사격해!!","JPN":"くっそ、そんなのわかっている！！　死にたくなければしっかり照準射撃しろ！！","ENG":"Dammit. Don't you think I know? If you don't wanna die, stay sharp and aim before you shoot!!","TWN":"該死的！我眼睛又沒瞎！不想死的話，就冷靜下來瞄準射擊！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"제기랄…… 성황청은 분명 이번 성무가 대인 작전이라고 했어요.","JPN":"ちくしょう……聖皇庁は確かに今回の聖務は対人作戦だって言ってたんです。","ENG":"Damn...! The Holy Curia clearly said that this sacred mission was gonna be an anti-personnel operation!","TWN":"該死的……聖皇廳明明說這次作戰的對象是人。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"그런데 저건 뭡니까? 침식체잖아요!! 게다가 저렇게 쏟아지는데!!","JPN":"なのにあれは何ですか？　侵食体じゃないですか！！　しかもあんなに大量の！！","ENG":"But do you see that?! Those are C.O.s!! And they just keep pouring out!!","TWN":"搞什麼鬼？根本就是侵蝕體！！而且數量還那麼多！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CLARK_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"성황청이 우릴 속였어요! 우린 버려진 겁니다! 여기서 다 죽을 거라고요!!","JPN":"聖皇庁が俺たちを騙したんです！　俺たちは捨てられたんですよ！　みんなここで死ぬんです！！","ENG":"The Holy Curia deceived us! They threw us under the bus! We're all gonna die out here!!","TWN":"聖皇廳騙我們！竟然擺我們一道！我們全都會死在這裡！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"이 새끼가 말 다했어? 헌금 받아먹고 사는 주제에 그런 말이 입에서 나와!?","JPN":"この野郎、なんだと？　献金で食わせてもらってるくせに、なんてことを言うんだ！？","ENG":"Shut it, will you?! You got a big mouth for someone who lives off of church donations!","TWN":"你這臭小子說完沒？靠人家養活還敢說那種話！？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"두 분 다 그만하세요!!","JPN":"お二人とも、おやめください！！","ENG":"Please stop it, the both of you!!","TWN":"都別再說了！！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_VATICAN_SUPPLEMENT_NULL","text":{"KOREA":"수녀님!?","JPN":"シスター！？","ENG":"Sister?!","TWN":"修女！？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"CLARK_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_VATICAN_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"헤밍턴 형제님 말씀이 옳아요. 이번 성무는 어디서부터인가 어긋났어요.","JPN":"ハミントン兄弟のおっしゃるとおりですわ。今回の聖務はどこか食い違いがあるようです。","ENG":"Brother Hammington is right. Something isn’t right about this sacred mission.","TWN":"海明頓弟兄說的沒錯，這次的聖務確實哪裡不對勁。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"침식체들의 움직임도 심상치 않아요.","JPN":"侵食体の動きも尋常ではありません。","ENG":"Even the C.O.s are behaving strangely.","TWN":"侵蝕體的行動也不太正常。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"습격과 도주를 거듭하면서 우리를 숲 속 깊은 곳으로 몰아넣고 있어요. 굉장히 교활하고, 치밀하게요.","JPN":"襲撃と逃走をくり返しながら、私たちを森の奥深くに追い込んでいます。とても狡猾かつ細緻に。","ENG":"They are using cunning tactics to ambush us and then retreat, ultimately driving us deeper into the forest.","TWN":"他們一下偷襲，一下又逃跑，就是想把我們逼到森林深處，行為非常地狡猾而且有組織性。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};